<?php
namespace App\Filament\Resources;
use App\Filament\Resources\PartnerResource\Pages; use App\Models\Partner; use Filament\Actions\BulkActionGroup; use Filament\Actions\DeleteBulkAction; use Filament\Actions\EditAction; use Filament\Forms\Components\FileUpload; use Filament\Forms\Components\TextInput; use Filament\Forms\Components\Toggle; use Filament\Resources\Resource; use Filament\Schemas\Schema; use Filament\Tables\Columns\IconColumn; use Filament\Tables\Columns\ImageColumn; use Filament\Tables\Columns\TextColumn; use Filament\Tables\Table;
class PartnerResource extends Resource { protected static ?string $model=Partner::class; protected static ?string $navigationLabel='პარტნიორები'; public static function form(Schema $schema):Schema{return $schema->components([TextInput::make('name')->label('სახელი')->required(),FileUpload::make('logo')->image()->disk('public')->directory('partners'),TextInput::make('url')->url(),TextInput::make('category')->label('კატეგორია'),Toggle::make('is_active')->default(true),TextInput::make('sort_order')->numeric()->default(0)]);} public static function table(Table $table):Table{return $table->columns([ImageColumn::make('logo')->disk('public'),TextColumn::make('name')->searchable(),TextColumn::make('category'),IconColumn::make('is_active')->boolean()])->defaultSort('sort_order')->recordActions([EditAction::make()])->toolbarActions([BulkActionGroup::make([DeleteBulkAction::make()])]);} public static function getPages():array{return ['index'=>Pages\ListPartners::route('/'),'create'=>Pages\CreatePartner::route('/create'),'edit'=>Pages\EditPartner::route('/{record}/edit')];}}
